							function Append(id, arr1, arr2, keyArr)
{                             
	var childs, t, d, obj;

	for (t=0; t!=arr1.length; t++)
	{                         
		obj=arr1[t];

		if (obj[keyArr]) 
			childs=obj[keyArr];
		else                 
			childs=obj[keyArr]=new Array();

		if (obj.id!=id) continue;

		for (d=0; d!=arr2.length; d++)
			childs.push(arr2[d]);
	}
}

