							//						   
function DrawIMG(src, style, width, height, title)
{
 	var retval="";

	retval+='(#CHAR.LT#)img src="'+src+'" style="'+style+'" width="'+width+'" height="'+height+'" title="'+title+'" /(#CHAR.GT#)';

	return retval;
}  

function DrawARROW(height)
{
	var retval;

	retval=DrawDIV(
		"", 
		"position:relative;margin:auto;width:5px;height:"+height+"px;", 
			DrawDIV(
					"", 
					"position:absolute;left:4px;top:4px;width:1px;height:"+(height-6)+"px;background-color:#AAA;", 
					""
			)+
			DrawDIV(
					"", 
					"border:5px solid transparent;border-top:5px solid #AAA;position:absolute;left:0px;top:"+(height-7)+"px;height:0px;width:0px;", 
					""
			)
		);

	return retval;
}

function DrawDIV(className, style, innerHTML)
{
 	var retval="";

	retval+='(#CHAR.LT#)div class="'+className+'" style="'+style+'" (#CHAR.GT#)';
	retval+=innerHTML;
	retval+='(#CHAR.LT#)/div(#CHAR.GT#)';

	return retval;
}

function DrawBUTTON(className, style, title, onClick)
{
  return '(#CHAR.LT#)button type="button" style="'+style+'" onclick="'+onClick+'" title="'+title+'" class="'+className+'" (#CHAR.GT#) (#CHAR.LT#)/button(#CHAR.GT#)'
}

function ExpandRoles()
{
	var reference=document.getElementById("ROLES");	
	if (reference.className=="DIV_REFERENCE CON")
		reference.className="DIV_REFERENCE EXP";
	else
		reference.className="DIV_REFERENCE CON";
}

function ExpandEstados()
{
	var reference=document.getElementById("ESTADOS");	
	if (reference.className=="DIV_REFERENCE CON")
		reference.className="DIV_REFERENCE EXP";
	else
		reference.className="DIV_REFERENCE CON";
}           

function ExpandParam(MyID, obj)
{
	if (ParamsContract["K"+MyID])
	{                           
		ParamsContract["K"+MyID]=false;
		obj.className="EXPAND EXP";
	} else
	{                              
		ParamsContract["K"+MyID]=true;
		obj.className="EXPAND CON";
	}              
	RefreshProcess();
}


function RolesContexMenu(MyID,event)
{
	var t;
	for (t=0; t!=Roles.length; t++)
		if (Roles[t].id==MyID)
		{
			parent.RolesContexMenu(oi_organigrama, Roles[t].id,Roles[t].COD, event, window);
			return;
		}
}

function EstadosContexMenu(MyID,event)
{
	var t;
	for (t=0; t!=Estados.length; t++)
		if (Estados[t].id==MyID)
		{
			parent.EstadoContexMenu(oi_wf, Estados[t].id, event, window);
			return;
		}
}

function NodeContexMenu(MyID,event)
{
	var t,d,Proceso,Nodo;

	for (t=0; t!=Procesos.length; t++)
	{              
		Proceso=Procesos[t];
		if (Proceso.Nodos)
		for (d=0; d!=Proceso.Nodos.length; d++)
		{                         
			Nodo=Proceso.Nodos[d];
			if (Nodo.id==MyID)                                         
			{
				parent.NodeContexMenu(Proceso.id,MyID,Nodo.TYP,event,window);
				return;
			}
		}
	}   
}           

function ParamContexMenu(MyID,event)
{
	var t,d,i,Proceso,Nodo, Param;

	for (t=0; t!=Procesos.length; t++)
	{              
		Proceso=Procesos[t];
		if (Proceso.Nodos)
		for (d=0; d!=Proceso.Nodos.length; d++)
		{                         
			Nodo=Proceso.Nodos[d];   

			if (Nodo.Params)
			for (i=0; i!=Nodo.Params.length; i++)
			{
				Param=Nodo.Params[i];
				if (Param.id==MyID)
				{
					parent.SubProcessContexMenu(Nodo.id,Param.PRO,event,window);
					return;
				}
			}
		}
	}   
}           

function NodeNewContexMenu(MyID,MyOrder,event)
{
	var t,d,Proceso,Nodo;

	for (t=0; t!=Procesos.length; t++)
	{              
		Proceso=Procesos[t];    
		if (Proceso.id==MyID)                                         
		{
			parent.NodeNewContexMenu(Proceso.id,MyOrder,event,window);
			return;
		}
	}
}           

function ParamNewContexMenu(MyID,event)
{
	var t,d,i,Proceso,Nodo, Param;

	for (t=0; t!=Procesos.length; t++)
	{              
		Proceso=Procesos[t];
		if (Proceso.Nodos)
		for (d=0; d!=Proceso.Nodos.length; d++)
		{                         
			Nodo=Proceso.Nodos[d];   
			if (Nodo.id==MyID)
			{
				parent.SubProcessNewContexMenu(Nodo.id,event,window);
				return;
			}
		}
	}   
}           





function RefreshRoles()
{   
	var t,d,f,rol,roles, row, cell, CNT,d;

	RolesKey=new Array();

	//obtengo la tabla de roles
	roles=document.getElementById("ROLES_TABLE");	
	for (t=0; t!=Roles.length; t++)
	{
		//Busco el ROL
		row=document.getElementById("ROL_"+Roles[t].id);	
		if (row) 
		{
			while(row.cells.length!=0)
				row.deleteCell(0);
		} else
		{
			//Agrego el ROL
			row=roles.insertRow(-1);	
			row.id="ROL_"+Roles[t].id;   
		}   

		cell=row.insertCell(-1);
		cell.className="GRP "+(Roles[t].COD=="OWNER"?"OWN":(Roles[t].UNQ?"UNQ":"MUL"));
		cell.innerHTML=DrawBUTTON("EDIT", "", "Mostrar el Menu", "RolesContexMenu("+Roles[t].id+",event);");
		cell.style.backgroundColor="#"+Roles[t].COL;

		cell=row.insertCell(-1);
		cell.className="DES";
		cell.innerHTML=Roles[t].DES;
		cell.title=Roles[t].DES;

		cell=row.insertCell(-1);
		cell.className="EST";
		if (Roles[t].COD!="OWNER")
		{
			if (Roles[t].INI==1)
				cell.innerHTML='(#CHAR.LT#)img src="Skins/_Default/Images/Workflow/tick.gif" width="16px" height="16px" /(#CHAR.GT#)'; 
			else
				cell.innerHTML='(#CHAR.LT#)img src="Skins/_Default/Images/Workflow/cross.gif" width="16px" height="16px" /(#CHAR.GT#)'; 
		}	


		//Agrego el ROL a la lista
		RolesKey[Roles[t].COD]=Roles[t];
	}   

	//Elimino los ROLES
	if (OldRoles)
	for (t=0; t!=OldRoles.length; t++)
	{  
		//Busco que el rol viejo
		f=false;           
		for (d=0; d!=Roles.length; d++)	if (Roles[d].id==OldRoles[t].id) f=true;

		if (!f)
		{
			//Busco el ROL
			row=document.getElementById("ROL_"+OldRoles[t].id);	

			//Elimino el Row
			roles.deleteRow(row.rowIndex);
		}
	}
}       


function RefreshEstados()
{   
	var t,d,f,estado,estados,row,cell;

	EstadosKey=new Array();

	//obtengo la tabla de Estados
	estados=document.getElementById("ESTADOS_TABLE");	
	for (t=0; t!=Estados.length; t++)
	{
		//Busco el ESTAO
		row=document.getElementById("ESTADO_"+Estados[t].id);	
		if (row) 
		{
			while(row.cells.length!=0)
				row.deleteCell(0);
		} else
		{
			//Agrego el ROL
			row=estados.insertRow(-1);	
			row.id="ESTADO_"+Estados[t].id;   
		}   

		cell=row.insertCell(-1);
		cell.className="GRP";
		cell.innerHTML=DrawBUTTON("EDIT", "", "Mostrar el Menu", "EstadosContexMenu("+Estados[t].id+",event);");
		cell.style.backgroundColor="#"+Estados[t].COL;

		cell=row.insertCell(-1);
		cell.className="COD";         
		cell.innerHTML=Estados[t].COD;
		cell.title=Estados[t].COD;

		cell=row.insertCell(-1);
		cell.className="DES";
		cell.innerHTML=Estados[t].DES;
		cell.title=Estados[t].DES;


		//Agrego el ESTADO a la lista
		EstadosKey[Estados[t].COD]=Estados[t];
	}   

	//Elimino los ESTADOS          
	if (OldEstados)
	for (t=0; t!=OldEstados.length; t++)
	{  
		//Busco que el rol viejo
		f=false;           
		for (d=0; d!=Estados.length; d++)	if (Estados[d].id==OldEstados[t].id) f=true;

		if (!f)
		{
			//Busco el ROL
			row=document.getElementById("ESTADO_"+OldEstados[t].id);	

			//Elimino el Row
			estados.deleteRow(row.rowIndex);
		}
	} 
}       


var Labels=new Array();
var Gotos=new Array();
function CalcProcess(proceso)
{     
	var retval;
	var nodo, t;
	var param, p;
	var child, tot, d, dif;

 	retval={Width:0, Height:0};

 	if (proceso.Nodos)
	for (t=0; t!=proceso.Nodos.length; t++)
	{                      
		//Obtengo el Proceso
		nodo=proceso.Nodos[t];
		nodo.Show=false;

		switch(nodo.TYP)
		{
			case "INI":   
				nodo.Width =80; nodo.TotalWidth =80;
				nodo.Height=22; nodo.TotalHeight=22;
				nodo.Space =20;
				break;

			case "FIN":
			case "STOP":
				nodo.Width =80; nodo.TotalWidth =80;
				nodo.Height=22; nodo.TotalHeight=22;
				nodo.Space = 0;
				break;

			case "LABEL":
				nodo.Width=120; nodo.TotalWidth=120;
				nodo.Height=29; nodo.TotalHeight=29;
				nodo.Space =20;

				if (Labels[nodo.DES])
					Labels[nodo.DES].Count++;
				else
					Labels[nodo.DES]={Count:1, Ref:0, Nodo:nodo};
				break;

			case "GOTO":
				nodo.Width=120; nodo.TotalWidth=120;
				nodo.Height=29; nodo.TotalHeight=29;
				nodo.Space = 0;

				if (Labels[nodo.DES])     
					Labels[nodo.DES].Ref++;

				Gotos.push(nodo);
				break;

			case "STATUS":
			case "WAIT_TO":
			case "WAIT_TIME": 
				nodo.Width=200; nodo.TotalWidth=200;
				nodo.Height=29; nodo.TotalHeight=29;
				nodo.Space =20;
				break;    

			case "PAR":	
			case "SWITCH":
				nodo.Width=200; nodo.TotalWidth=200;
				nodo.Height=25; nodo.TotalHeight=25;
				nodo.Space =20;

				//Calculo el los elementos Hijos
				tot={Width:0, Height:60};
				for (p=0; p!=nodo.Params.length; p++)
				{
					param=nodo.Params[p];
					param.ProcessChild=null;

					//Busco el Proceso Asociado
					for (d=0; d!=Procesos.length; d++)
					if (Procesos[d].AUT==param.PRO)
					{
						param.ProcessChild=Procesos[d];
						break;
					}

					if (param.ProcessChild)
					{					                
						child=CalcProcess(param.ProcessChild);
						if (ParamsContract["K"+param.id])
						{
							child={Width:100, Height:60};
						} else
						{
							if (child.Width(#CHAR.LT#)100) child.Width=100;
							child.Height+=60;
						}
					} else
					{       
						child={Width:100, Height:60};
					}       

					param.Width =child.Width;
					param.Height=child.Height;

					tot.Width+=param.Width;
					if (tot.Height(#CHAR.LT#)param.Height) tot.Height=param.Height;
				}              

				if (nodo.Width(#CHAR.LT#)tot.Width-20) nodo.Width=tot.Width-20;
				                                  else tot.Width=nodo.Width+20;

				if (nodo.TotalWidth(#CHAR.LT#)tot.Width) nodo.TotalWidth=tot.Width;
				nodo.TotalHeight=nodo.Height+tot.Height;

				//Actualizo los Paramemtros Nuevamente				
				for (p=0; p!=nodo.Params.length; p++)
				{
					param=nodo.Params[p];
					dif=tot.Height-param.Height;

					//Calculo la altura de cada parametro
					param.Height+=dif;   

					if (param.ProcessChild)
					if (param.ProcessChild.Nodos)
					if (param.ProcessChild.Nodos.length)
						if (param.ProcessChild.Nodos[param.ProcessChild.Nodos.length-1].Space!=0)
							param.ProcessChild.Nodos[param.ProcessChild.Nodos.length-1].Space+=dif;
				}   
				break;


			//Nodo estandar
			default:
				nodo.Width=200; nodo.TotalWidth=200;
				nodo.Height=40; nodo.TotalHeight=40;
				nodo.Space =20;
				break;
		}               

		//Calculo la Altura		          
		retval.Height+=nodo.TotalHeight+nodo.Space;

		//Calculo el Ancho
		if (retval.Width(#CHAR.LT#)nodo.TotalWidth) retval.Width=nodo.TotalWidth;
	}

	retval.Width+=20;                             
	proceso.Width =retval.Width;
	proceso.Height=retval.Height;

	return retval;
}     

function RefreshNode(nodo, error, warning)
{
	var t, retval, text;

	retval="";      


	switch(nodo.TYP)
	{
		case "INI": text=DrawDIV("TEXT BOLD","position:absolute;left:22px;top:2px;width:"+(nodo.Width-26)+"px;","Inicio"); break;
		case "FIN": text=DrawDIV("TEXT BOLD","position:absolute;left:22px;top:2px;width:"+(nodo.Width-26)+"px;","Fin"); break;
		case "STOP": text=DrawDIV("TEXT BOLD","position:absolute;left:22px;top:2px;width:"+(nodo.Width-26)+"px;","Terminar"); break;

		default: text=DrawDIV("TEXT BOLD","position:absolute;left:22px;top:2px;width:"+(nodo.Width-26)+"px;",nodo.DES); break;
	}         


	retval=DrawDIV(
	          "NODE_SHOW" +(error!=""?" ERROR":""),
	          "width:"+nodo.Width+"px;height:"+nodo.Height+"px;",
	          DrawIMG("skins/_default/Images/Workflow/Define/"+nodo.TYP+".gif","position:absolute;left:3px;top:2px;", 16,16, "")+
	          text+
	          DrawBUTTON("EDIT", "top:3px;left:4px", "Mostrar el Menu", "NodeContexMenu("+nodo.id+",event);")+

	          (error!=""?
	          	DrawIMG("skins/_default/Images/Workflow/Logs/ERR.gif","position:absolute;bottom:5px;right:5px;",16,16,error):
	          	(warning!=""?DrawIMG("skins/_default/Images/Workflow/Logs/WRN.gif","position:absolute;bottom:5px;right:5px;",16,16,warning):"")
	          )
	        );


	return retval;
}

function RefreshParams(proceso, nodo)
{                           
	var p, param;
	var left, retval, leftCorrect, leftCorrect2;
	var ord, child, top; 

  //Ancho de los Parametros
	width=0;
	for (p=0; p!=nodo.Params.length; p++)
		width+=nodo.Params[p].Width;


	leftCorrect =Math.round((proceso.Width-width)/2);
	leftCorrect2=nodo.Left-Math.round(width/2);

	retval="";
	left=0; 
	for (p=0; p!=nodo.Params.length; p++)
	{                  
		top=nodo.Top+nodo.Height+2;
		param=nodo.Params[p];

		child=DrawDIV(
	          "NODE_SHOW",
	          "width:80px;height:25px;",

	          DrawIMG("skins/_default/Images/Workflow/Define/SUB_PROCESS.gif","position:absolute;left:5px;top:5px;", 16,16, "")+
	          DrawDIV("TEXT BOLD","position:absolute;left:25px;top:5px;width:50px;",param.DES)+
	          DrawBUTTON("EDIT", "top:5px;left:6px", "Mostrar el Menu", "ParamContexMenu("+param.id+",event);")+
	          DrawBUTTON("EXPAND EXP", "top:4px;right:-2px", "Expandir/Contraer el Subproceso", "ExpandParam("+param.id+",this);")
	        ); 
	  top+=27;

		if (param.ProcessChild)
		{       
			if (ParamsContract["K"+param.id]?false:true)
			{
				if (param.ProcessChild.Nodos.length!=0)
					ord=Math.round(param.ProcessChild.Nodos[0].ORD /2);
				else
					ord=65536;

				child+=DrawDIV("NODE_JOIN","width:"+param.Width+"px;height:20px;", 
					DrawARROW(nodo.Space)+
					DrawBUTTON("ADD", "top:4px;left:"+Math.round(param.Width/2-5)+"px", "Mostrar el Menu", "NodeNewContexMenu("+param.ProcessChild.id+","+ord+",event);")
				);                       
				top+=20;

		    param.ProcessChild.Top =top;
		    param.ProcessChild.Left=left+leftCorrect2;
				child+=RefreshProcessChild(param.ProcessChild);     
			} 
		}  

		retval+=DrawDIV(
		          "NODE_PARAM",
		          "left:"+(left+leftCorrect)+"px;top0px;width:"+param.Width+"px;height:"+param.Height+"px;",
		          child
		        );            

		left+=param.Width;  
	}              

	return retval;
}

function RefreshProcessChild(proceso)
{
	var t, nodo;
	var retval, error, warning, fin;
	var top, left; 
	var cont;

	top =proceso.Top;
	left=proceso.Left+Math.round(proceso.Width/2);

	retval=""; error=""; warning=""; fin=false; 
	for (t=0; t!=proceso.Nodos.length; t++)
	{
		error=""; warning="";

		//Obtengo el Proceso
		nodo=proceso.Nodos[t]; 
		nodo.Show=true;

		if (fin)
			error="No puede haber nodos despues de GOTO/FIN";

		//Verificacion 
		switch(nodo.TYP)
		{               
			case "LABEL":
				if (Labels[nodo.DES].Count!=1)
					error="Existe "+Labels[nodo.DES].Count+" etiquetas con el mismo nombre";
				else
				if (Labels[nodo.DES].Ref==0)
					warning="No hay ningun GOTO hacia esta Etiqueta";
				break;

			case "GOTO":
				if (Labels[nodo.DES]?false:true)
					error="No existe la etiqueta "+nodo.DES;
				break;

		}

		//Calculo la posision Vertical
		nodo.Top =top;             
		nodo.Left=left;
		switch(nodo.TYP)
		{
			case "SWITCH":
			case "PAR":
				cont=DrawDIV("NODE_SWITCH", "left:"+Math.round((proceso.Width-nodo.TotalWidth)/2)+"px;width:"+nodo.TotalWidth+"px;height:"+(nodo.TotalHeight+3)+"px;",
				       DrawBUTTON("ADD", "top:8px;right:-10px;", "Mostrar el Menu", "ParamNewContexMenu("+nodo.id+",event);")
			       	);

		    cont+=RefreshNode(nodo, error, warning);
		    cont+=RefreshParams(proceso, nodo);
				break;  

			case "FIN":
			case "STOP":
			case "GOTO":
				cont=RefreshNode(nodo, error, warning);        
				fin=true;
				break;  

			default:
				cont=RefreshNode(nodo, error, warning);
				break;
		}

		//Dibujo el NODO
		retval+=DrawDIV(
		          "NODE_CONTAIN",
		          "width:"+proceso.TotalWidth+"px;height:"+nodo.TotalHeight+"px;",
		          cont
		        );
		top+=nodo.TotalHeight;

		//espacio                                                       
		if (nodo.Space!=0) 
		{ 
			if(t+1!=proceso.Nodos.length)
				ord=Math.round((nodo.ORD+proceso.Nodos[t+1].ORD)/2);
			else                     
				ord=nodo.ORD+65536;

			retval+=DrawDIV("NODE_JOIN","width:"+proceso.Width+"px;height:"+nodo.Space+"px;", 
				DrawARROW(nodo.Space)+
				DrawBUTTON("ADD", "top:4px;left:"+Math.round(proceso.Width/2-5)+"px", "Mostrar el Menu", "NodeNewContexMenu("+proceso.id+","+ord+",event);")
			);

			top+=nodo.Space;
		}        

	}


	return retval;
}


function RefreshGoto()
{  
  var t,d, retval, nodo;
	var key, label, right, top, left;

  retval="";
  /*
	for (t=0; t!=Procesos.length; t++)
	for (d=0; d!=Procesos[t].Nodos.length; d++)
	{          
		nodo=Procesos[t].Nodos[d];
		if (nodo.Show)
			retval+=DrawDIV("","background-color:red;border:none;margin0px;padding:0px;position:absolute;top:"+(nodo.Top-1)+"px;left:"+(nodo.Left-1)+"px;height:3px;width:3px;","");
	}  
	*/


	for (key in Labels)
	{
		nodo=Labels[key].Nodo;
		nodo.Right=nodo.Left+105;
	}

	for (t=0; t!=Gotos.length; t++)
	{
		nodo=Gotos[t];        
		if (nodo.Show)
		{
			right=nodo.Left+105;
			top  =nodo.Top;
			left =0;

			label=Labels[nodo.DES];
			if (label)                                 
			{    
				if (label.Nodo.Show)
				{
					if (right (#CHAR.LT#) label.Nodo.Left+105) 
						right=label.Nodo.Left+105;

					top=label.Nodo.Top;

					if (label.Nodo.Right)
					{                    
						if (label.Nodo.Right (#CHAR.LT#) right)
							label.Nodo.Right=right;
					} else
						label.Nodo.Right=right;
				}
			}

			retval+=DrawDIV("","border-top:2px dotted #999; position:absolute;top:"+(nodo.Top+15)+"px;left:"+(nodo.Left+65)+"px;width:"+(right-(nodo.Left+65))+"px;height:1px;","");
			retval+=DrawDIV("","border-left:2px dotted #999;position:absolute;top:"+(top+15)+"px;left:"+(right-2)+"px;height:"+(nodo.Top-top)+"px;width:1px;","");
		}
	}

	for (key in Labels)
	{
		nodo=Labels[key].Nodo;
		if (nodo.Show)
		{
			retval+=DrawDIV("","border-top:2px dotted #999;position:absolute;top:"+(nodo.Top+15)+"px;left:"+(nodo.Left+65)+"px;width:"+(nodo.Right-(nodo.Left+65))+"px;height:1px;","");
			retval+=DrawDIV("","border:6px solid transparent;border-right:6px solid #999;position:absolute;top:"+(nodo.Top+10)+"px;left:"+(nodo.Left+58)+"px;width:0px;height:0px;","");
		}
	} 

	return retval;
}

function RefreshProcess()
{
	var child;

	Labels=new Array();
	Gotos=new Array();
	child=CalcProcess(Procesos[0]);

	//Calulo los Tamanos
	if (child.Width(#CHAR.LT#)200) Procesos[0].Width=child.Width=200;
	if (child.Height(#CHAR.LT#)100) Procesos[0].Height=child.Height=100;

	//Actualizo el Documento             
	Procesos[0].Top=0;
	Procesos[0].Left=0;

	document.getElementById("WORKFLOW").innerHTML=
	DrawDIV("MARGIN_TOP","","")+
	DrawDIV("PROCESS_ROOT",
					"width:"+Procesos[0].Width+"px;height:"+Procesos[0].Height+"px;", 
					RefreshProcessChild(Procesos[0])+
					RefreshGoto()
				);	
}

function Refresh(XML)
{                   
	if (XML)
	{ 
		OldRoles=Roles;
		Roles=new Array();
		for (cur=XML.FindElement("ROLES").FirstChild(); cur!=null; cur=cur.Next())
			Roles.push( {id:cur.GetAttrInt("id"), COD:cur.GetAttr("COD"), DES:cur.GetAttr("DES"), COL:cur.GetAttr("COL"), INI: cur.GetAttrInt("INI") , UNQ: cur.GetAttrInt("UNQ") } );

		OldEstados=Estados;
		Estados=new Array();
		for (cur=XML.FindElement("ESTADOS").FirstChild(); cur!=null; cur=cur.Next())
			Estados.push( {id:cur.GetAttrInt("id"), COD:cur.GetAttr("COD"), DES:cur.GetAttr("DES"), COL:cur.GetAttr("COL") } );

		OldProcesos=Procesos;
		Procesos=new Array();
		for (cur=XML.FindElement("PROCESS").FirstChild(); cur!=null; cur=cur.Next())
		{
			//Agrego el Proceso
			Proceso={id:cur.GetAttrInt("id"), COD:cur.GetAttr("COD"), DES:cur.GetAttr("DES"), AUT: cur.GetAttrInt("AUT") };
			Proceso.Nodos=new Array();
			Procesos.push(Proceso);

   		//Agrego los Nodos
			for (cur2=cur.FirstChild(); cur2!=null; cur2=cur2.Next())
			{
				Nodo={id:cur2.GetAttrInt("oi_node"), TYP:cur2.GetAttr("c_type"), DES:cur2.GetAttr("d_label"), ORD:cur2.GetAttrDouble("n_secuence") };
				Nodo.Params=new Array();
				Proceso.Nodos.push(Nodo);

	   		//Agrego los Parametros
				for (cur3=cur2.FirstChild(); cur3!=null; cur3=cur3.Next())
				{
					Param={id:cur3.GetAttrInt("oi_param"), DES:cur3.GetAttr("d_param"), TYP:cur3.GetAttr("c_type"), PRO:cur3.GetAttr("e_subproceso") };
					Nodo.Params.push(Param);
				}
			}
		}
	}

	RefreshRoles();
	RefreshEstados();
	RefreshProcess();
}

function OnLoad()
{  
	Refresh(null);
}

